solution:
s = input()
count = 0
for char in s:
    if char.lower() in 'aeiou':
        count += 1
print(count)

s = input()
if s.lower() == s.lower()[::-1]:
    print("Yes")
else:
    print("No")

text = input()
shift = int(input())
result = []
for ch in text:
    if 'a' <= ch <= 'z':
        result.append(chr((ord(ch) - ord('a') + shift) % 26 + ord('a')))
    elif 'A' <= ch <= 'Z':
        result.append(chr((ord(ch) - ord('A') + shift) % 26 + ord('A')))
    else:
        result.append(ch)
print(''.join(result))
